head.script:
/* ★AIcraft guide★    
스크립트 수작업 유의사항
*/




scwin.onpageload = function() {
	scwin.OnInitScreen();
};

scwin.onpageunload = function() {}; /*  조회 버튼 클릭 */
scwin.Button3_OnClick = async function(e) {
    $c.iz.tran.setTranID("KJM0470441");
    await $c.iz.tran.ASend();
    tranResnCtnt.setMandatory(true); //거래사유 입력 필수
};

scwin.OnEndTran = function() {
    if ($c.iz._tran.bError == true) return;
    if ($c.iz._tran.tranId == "KJM0470441") {
        /* 관리번호로 조회 */

        if ($c.iz._tran.bError == false) {
            if (acitmPrcssDd.getValue() != "") {
                $c.iz.data.commonButtonEnable(0, true); //정리 버튼 활성화
                $c.iz.data.commonButtonEnable(1, true); //취소 버튼 활성화					
            }
            scwin.intgraTiaccCd_chk(); //통합계정과목기준 입지급 판정
        }
    }
    if (arngNo.getValue() == "001") {
        //발생내역
        tranAmtDstcd1.setDisabled(false); //금액1
        tranAmt1.setDisabled(false); //금액1
        tranAmtDstcd2.setDisabled(false); //금액1
        tranAmt2.setDisabled(false); //금액2
        tranResnCtnt.setDisabled(false); //거래사유내용
        dtailTranResn.setDisabled(false); //상세거래사유내용
        if (inotStusDsticName1.getValue() == "입금") {
            ondmd.setDisabled(false); //요구불 체크박스
        } else {
            ondmd.setDisabled(true); //요구불 체크박스
        }
        intnlrmtRvsex.setDisabled(false); //전금/역환 체크박스
        $c.iz.data.commonButtonEnable(0, true); //정리 버튼 활성화
        $c.iz.data.commonButtonEnable(1, false); //취소 버튼 비활성화					
    } else {
        tranAmtDstcd1.setDisabled(true); //금액1
        tranAmt1.setDisabled(true); //금액1
        tranAmtDstcd2.setDisabled(true); //금액1
        tranAmt2.setDisabled(true); //금액2
        tranResnCtnt.setDisabled(true); //거래사유내용
        dtailTranResn.setDisabled(true); //상세거래사유내용
        ondmd.setDisabled(true); //요구불 체크박스
        intnlrmtRvsex.setDisabled(true); //전금/역환 체크박스
        $c.iz.data.commonButtonEnable(0, false); //정리 버튼 비활성화
        $c.iz.data.commonButtonEnable(1, true); //취소 버튼 비활성화					
    }
};

/* 요구불 체크박스 클릭 */
scwin.ondmd_OnItemChanged = function(info) {
    if (ondmd.getValue() == "1") {
        trsaccAcno.setDisabled(false);
        Button4.setDisabled(false);
        reqnm.setDisabled(false);
        reqnm.setValue("KB " + $c.user.getUserProfile('userBzwkBrnName'));
        trsaccAcno.setMandatory(true);
        reqnm.setMandatory(true);
        GroupBox8.setValue("");
        GroupBox8.setDisabled(true);
    } else if (ondmd.getValue() == 0) {
        trsaccAcno.setDisabled(true);
        Button4.setDisabled(true);
        reqnm.setDisabled(true);
        trsaccAcno.setValue("");
        Button4.setValue("");
        reqnm.setValue();
        dpstrName.setValue();
        trsaccAcno.setMandatory(false);
        reqnm.setMandatory(false);
        GroupBox8.setDisabled(false);
    }
};
/* 요구불계좌번호 검증 -> 예금주명 가져오기 */
scwin.trsaccAcno_OnValidate = function(info) {
    $c.com.queryCustNameByAccount('1', trsaccAcno, '000', dpstrName);
};
/* 전금역환 체크박스 클릭 */
scwin.intnlrmtRvsex_OnItemChanged = function(info) {
    if (intnlrmtRvsex.getValue() == "1") {
        /*ondmd.Value = "0";
        ondmd_ControlEnble(false);
        ondmd_ControlClear();
        intnlrmtRvsex_ControlEnable(true);*/
        GroupBox4.setValue("");
        GroupBox4.setDisabled(true);
        inwrBrncd.setDisabled(false);
        Button5.setDisabled(false);
        mnrcvBnkCd.setDisabled(false);
        acno.setDisabled(false);
        drblCtnt1.setDisabled(false);
        drblCtnt2.setDisabled(false);
        inwrBrncd.setMandatory(true);
        drblCtnt1.setMandatory(true);
    } else if (intnlrmtRvsex.getValue() == 0) {
        GroupBox4.setDisabled(false);
        inwrBrncd.setDisabled(true);
        Button5.setDisabled(true);
        mnrcvBnkCd.setDisabled(true);
        acno.setDisabled(true);
        drblCtnt1.setDisabled(true);
        drblCtnt2.setDisabled(true);
        inwrBrncd.setValue("");
        Button5.setValue("");
        mnrcvBnkCd.clear();
        acno.setValue();
        drblCtnt1.setValue();
        drblCtnt2.setValue();
        inwrBrnName.setValue();
        drblNo.setValue();
        inwrBrncd.setMandatory(false);
        drblCtnt1.setMandatory(false);
    }
};

scwin.intnlrmtRvsex_ControlEnable = function(State) {
    inwrBrncd.setDisabled(State);
    mnrcvBnkCd.setDisabled(State);
    acno.setDisabled(State);
    drblCtnt1.setDisabled(State);
    drblCtnt2.setDisabled(State);
    inwrBrncd.setDisabled(State);
};

scwin.intnlrmtRvsex_ControlClear = function() {
    inwrBrncd.setValue();
    mnrcvBnkCd.clear();
    drblNo.setValue();
    acno.setValue();
    drblCtnt1.setValue();
    drblCtnt2.setValue();
    inwrBrncd.setValue();
    inwrBrnName.setValue();
};

scwin.ondmd_ControlEnble = function(State) {
    Button4.setDisabled(State);
    trsaccAcno.setDisabled(State);
    reqnm.setDisabled(State);
};

scwin.ondmd_ControlClear = function() {
    trsaccAcno.setValue();
    dpstrName.setValue();
    reqnm.setValue();
};

scwin.LinkText1_OnClick = function(e) {
    //정리내역조회			KJM04706000	
    //계정처리일(acitmPrcssDd) -> KJM04706000화면의
    //조회시작일(inquryStartDd)과 조회종료일(inquryEndDd) 에 SETTING하여 화면 연동처리

    Link.inquryStartDd = acitmPrcssDd.getValue();
    Link.inquryEndDd = acitmPrcssDd.getValue();
    Link.brncd = $c.user.getUserProfile('userBzwkBrncd');
    $c.iz.screen.screenOpen("KJM04706000", "DATALINK");
};

scwin.LinkText2_OnClick = function(e) {
    //기본원장내역조회			KJM04703000	
    //발생일자(occurDte) -> KJM04703000화면의
    //조회시작일(inquryStartDd)과 조회종료일(inquryEndDd) 에 SETTING하여 화면 연동처리

    Link.inquryStartDd = occurDte.getValue();
    Link.inquryEndDd = occurDte.getValue();
    Link.brncd = mgtNo.getValue().substr(6, 4);
    $c.iz.screen.screenOpen("KJM04703000", "DATALINK");
};

scwin.LinkText3_OnClick = function(e) {
    //관리번호별정리내역			KJM04705000	
    //관리번호(mgtNo) ->  KJM04705000화면의 관리번호(mgtNo)에 SET 하여 
    //화면 연동처리

    Link.mgtNo = mgtNo.getValue();
    $c.iz.screen.screenOpen("KJM04705000", "DATALINK");
};


scwin.tranAmtSum_Fun = function() {
    var strtranAmt1 = tranAmt1.getValue();
    var strtranAmt2 = tranAmt2.getValue();
    var strtranAmtSum = 0;
    if (strtranAmt1 == "") {
        strtranAmt1 = 0;
    }
    if (strtranAmt2 == "") {
        strtranAmt2 = 0;
    }
    strtranAmtSum = parseInt(strtranAmt1) + parseInt(strtranAmt2);
    tranAmtSum.setValue(strtranAmtSum);
};

scwin.tranAmt1_OnValidate = function(info) {
    //금액1
    scwin.tranAmtSum_Fun();
};

scwin.tranAmt2_OnValidate = function(info) {
    //금액2
    scwin.tranAmtSum_Fun();
};

scwin.Button4_OnClick = function(e) {
    //여기에 구현코드를 삽입하세요.
    $c.iz.screen.popup("KJM06758001", "DATALINK");
    var strtrsaccAcno = Link.trsaccAcno;
    if (strtrsaccAcno != "" && typeof(strtrsaccAcno) != "undefined") {
        trsaccAcno.setValue(strtrsaccAcno);
    }
};

scwin.Button5_OnClick = function(e) {
    //여기에 구현코드를 삽입하세요.
    $c.iz.screen.popup("KJI04811000", "DATALINK");
    var strbrncd = Link.brncd;
    var strbrnName = Link.brnName;
    var strbrnHanglName = Link.brnHanglName;
    if (strbrncd != "" && typeof(strbrncd) != "undefined") {
        inwrBrncd.setValue(strbrncd);
        inwrBrnName.setValue(strbrnHanglName);
    }
};

scwin.inwrBrncd_OnValidate = function(info) {
    //여기에 구현코드를 삽입하세요.
    $c.com.getCommonBrnName(inwrBrncd, inwrBrnName);
};

scwin.OnInitScreen = async function() {
    //여기에 구현코드를 삽입하세요.
    if (mgtNo.getValue() != "") {
        $c.iz.tran.setTranID("KJM0470441");
        await $c.iz.tran.ASend();
        tranResnCtnt.setMandatory(true); //거래사유 입력 필수
    }
};
/* 정리 버튼 */
scwin.OnSendKey = async function() {
    if (acctgDstic.getValue() == "") {
        $c.iz.data.message("관리번호를 입력하여 조회를 먼저 한후 거래하시기 바랍니다.");
        return;
    }
    if (arngNo.getValue() != "001") {
        $c.iz.data.message("관리번호옆 정리번호에 공란(또는 001)을 입력하여 조회를 먼저 한후 거래하시기 바랍니다.");
        return;
    }
    if (tranAmtSum.getValue() == 0) {
        $c.iz.data.message("정리할 금액을 입력하세요. ");
        tranAmtDstcd1.focus();
        return;
    }
    if (tranResnCtnt.getValue() == "") {
        $c.iz.data.message("거래사유를 입력하세요. ");
        tranResnCtnt.focus();
        return;
    }
    $c.iz.tran.setTranID("KJM0670461");
    await $c.iz.tran.ASend();
};
/* (정리)취소 버튼 */
scwin.OnSendKey2 = function() {
    //1. 취소버튼을 누르면 KJM04701001화면을 호출한다
    //2. corrcCnclDstic 에 '9'를 set 한다.
    //3. 이체계좌번호(trsaccAcno) 또는 타발점코드(inwrBrncd)에 값이없으면, KJM04701001화면의 연동유무(cupldEonot)에 '0'을 있으면 '1'을 set한다
    //4. 거래일자(tranDte) 를 KJM04701001화면의 거래일자(tranDte) 에 set 한다.
    //5. 거래시각(tranHMS)을 KJM04701001화면의 거래시각(tranHMS)에 set 한다.
    //6. 부점코드(brncd) 를 KJM04701001 화면의 거래부점(trbrn)에 set 한다. 
    //7. 관리번호(mgtNo)를 KJM04701001 화면의 관리번호(mgtNo)에 set 한다
    //8. 정리번호(arngNo)를 KJM04701001 화면의 정리번호(arngNo)에 set 한다
    //9. 직원번호(tranEmpid)를 KJM04701001 화면의 직원번호(tranEmpid)에 set 한다.
    //10. KJM04701001의 거래유형(tranPtrn)은 거래금액합계(tranAmtSum)와 대체금액(trfamt)이 같으면 '대체'를 대체금액(trfamt)이 '0'이면 '현금'을 set 하고 
    //     대체금액(trfamt)이 '0'이 아닌데 거래금액합계(tranAmtSum)와 대체금액(trfamt)이 다르면 '일부대체' 라고 표시한다.
    //11. 거래금액합계(tranAmtSum) 을 KJM04701001화면의 거래금액(tranAmt)에 set 한다.
    //12. KJM04701001화면의 거래코드(tranCd)는 'KJM0670461'를 set한다.
    //13. 원거래일시(ogtranYMS) 은 KJM04701001 화면의 원거래일시(ogtranYMS) set한다.
    //14. 통합전문고유번호(intgraTelgmUniqno)  은 KJM04701001 화면의 통합전문고유번호(intgraTelgmUniqno)set한다.
    //15. 취소복원영역(cnclRstrScop)  은 KJM04701001 화면의 취소복원영역(cnclRstrScop) set한다.

    if (acctgDstic.getValue() == "") {
        $c.iz.data.message("관리번호를 입력하여 조회를 먼저 한후 거래하시기 바랍니다.");
        return;
    }
    if (arngNo.getValue() == "001" || tranYmd.getValue() == "") {
        $c.iz.data.message("발생거래는 취소대상 거래가 아닙니다. 관리번호옆 정리번호를 입력하여 조회를 먼저 한후 거래하시기 바랍니다.");
        mgtNo.focus();
        return;
    }
    if (orglArngNo.getValue() != "000") {
        $c.iz.data.message("해당 거래는 이미 취소된 거래입니다. 관리번호별정리내역조회(04-73-009)로 확인하시기 바랍니다.");
        return;
    }
    if (tranDte.getValue() != $c.user.getUserProfile('tranBaseYmd')) {
        $c.iz.data.message("취소거래는 당일 발생분만 가능합니다.");
        return;
    }
    Link.corrcCnclDstic = "9";
    if ($c.iz.data.trim(trsaccAcno.getValue()) == "" && $c.iz.data.trim(inwrBrncd.getValue()) == "") {
        Link.cupldEonot = "0";
    } else {
        Link.cupldEonot = "1";
    }
    Link.tranDte = tranDte.getValue();
    Link.tranHMS = tranHMS.getValue();
    Link.trbrn = $c.user.getUserProfile('userBzwkBrncd');
    Link.mgtNo = mgtNo.getValue();
    Link.arngNo = arngNo.getValue();
    Link.empid = tranEmpid.getValue();
    var vtrfamt = 0; //대체금액

    if (tranAmtDstcd1.getValue() == "09") {
        //금액구분1:09-대체
        vtrfamt = Number(tranAmt1.getValue());
    }
    if (tranAmtDstcd2.getValue() == "09") {
        //금액구분2:09-대체
        vtrfamt = Number(vtrfamt) + Number(tranAmt2.getValue());
    }
    if (vtrfamt == 0) {
        Link.tranPtrn = "현금";
    } else {
        if (tranAmtSum.getValue() == vtrfamt) {
            Link.tranPtrn = "대체";
        } else {
            Link.tranPtrn = "일부대체";
        }
    }
    Link.tranAmt = tranAmtSum.getValue();
    Link.tranCd = "KJM0670461";
    Link.ogtranYMS = ogtranYMS.getValue();
    Link.intgraTelgmUniqno = intgraTelgmUniqno.getValue();
    Link.cnclRstrScop = cnclRstrScop.getValue();
    $c.iz.screen.popup("KJM04701001", "DATALINK");
};

scwin.mgtNo_OnValidate = function(info) {
    //관리번호
    $c.iz.data.commonButtonEnable(0, false); //정리 버튼 활성화
    $c.iz.data.commonButtonEnable(1, false); //취소 버튼 활성화					
    scwin.ClearScr(); //화면 클리어
    inotStusDsticName1.setValue();
    inotStusDsticName2.setValue();
};

scwin.arngNo_OnValidate = function(info) {
    var varngNo = arngNo.getValue();
    if (arngNo.getValue().length == 2) {
        varngNo = "0" + arngNo.getValue();
    } else if (arngNo.getValue().length == 1) {
        varngNo = "00" + arngNo.getValue();
    }
    arngNo.setValue(varngNo);
    scwin.ClearScr(); //화면 클리어
    inotStusDsticName1.setValue();
    inotStusDsticName2.setValue();
};

scwin.ClearScr = function() {
    //화면초기화
    GroupBox2.setValue("");
    GroupBox6.setValue("");
    GroupBox3.setValue("");
    GroupBox7.setValue("");
    GroupBox4.setValue("");
    GroupBox8.setValue("");
    GroupBox5.setValue("");
    ogtranYMS.setValue("");
    intgraTelgmUniqno.setValue("");
    cnclRstrScop.setValue("");
    dtailTranResn.setValue("");
    mnrcvBnkCd.setValue("");
    acno.setValue("");
    drblNo.setValue("");
    spvsrAthorResnName.setValue("");
    ondmd.setValue("0");
    intnlrmtRvsex.setValue("0");
    scwin.ondmd_OnItemChanged();
    scwin.intnlrmtRvsex_OnItemChanged();
};

scwin.intgraTiaccCd_chk = function() {
    //통합계정과목기준 입지급 판정
    if (intgraTiaccCd.getValue() == "") return;
    $c.iz.tran.setTranID("KJM0472041"); //계정과목검색
    $c.iz.tran.setInFDData("KJM0472041", "inquryCndn/acctgDstic", acctgDstic.getValue()); //회계구분
    $c.iz.tran.setInFDData("KJM0472041", "inquryCndn/bSISDstic", '0'); //BSIS구분:0-해당무
    $c.iz.tran.setInFDData("KJM0472041", "inquryCndn/acitmSerchDstic", '2'); //계정검색구분:2-계정코드
    $c.iz.tran.setInFDData("KJM0472041", "inquryCndn/acitmSerchName", intgraTiaccCd.getValue()); //계정검색명:계정과목코드
    $c.iz.tran.setInFDData("KJM0472041", "inquryCndn/tranDstic", '2'); //거래구분
    $c.iz.tran.WaitSend();
    if ($c.iz._tran.tranId == "KJM0472041") {
        if ($c.iz._tran.bError == false) {
            var GridData = $c.iz.tran.getOutMultiAllData("screen", "indxSerch/dataBook");
            var re = new RegExp("\x06\x05", "g");
            var re2 = new RegExp("\x06", "g");
            var comStr = GridData.replace(/\s/g, "").replace(re, ";").replace(re2, ":");
            var arrGridbrnCd = comStr.split(":");
            for (var i = 0; i < arrGridbrnCd.length; i++) {
                if (i == 2) //계정분류코드
                    var acitmDstic = arrGridbrnCd[i];
            }
        }
    }
    if (acitmDstic == "1" || acitmDstic == "6") {
        //계정분류코드:1-자산,6-비용
        inotStusDsticName1.setValue("출금");
        inotStusDsticName2.setValue("입금");
        if (arngNo.getValue() == "001") {
            tranAmtDstcd1.SetCondition("00,09,91,93"); //발생이 출금계정임으로 정리는 입금거래입
            tranAmtDstcd2.SetCondition("00,09,91,93");
        }
    } else {
        inotStusDsticName1.setValue("입금");
        inotStusDsticName2.setValue("출금");
        if (arngNo.getValue() == "001") {
            tranAmtDstcd1.SetCondition("00,09"); //발생이 입금계정임으로 정리는 출금거래임
            tranAmtDstcd2.SetCondition("00,09");
        }
    }
};
